import { impuestos } from "@/constants/impuestos";
import type { CotizacionItem } from "@/types/cotizacion-item";
import { calculateItemPrice } from "./calculateItemPrice";
import { calculateTotals } from "./calculateTotals";

export type CotizadorEngineItem = Pick<
  CotizacionItem,
  "cantidad" | "precioUnitario"
>;

export type CotizadorEngineInput = {
  items: CotizadorEngineItem[];
  ivaRate?: number;
};

export const cotizadorEngine = ({
  items,
  ivaRate = impuestos.iva,
}: CotizadorEngineInput) => {
  if (items.length === 0) {
    return {
      cantidadItems: 0,
      subtotal: 0,
      iva: 0,
      total: 0,
    };
  }

  const subtotal = items.reduce((accumulator, item) => {
    return accumulator + calculateItemPrice(item.precioUnitario, item.cantidad);
  }, 0);

  return {
    cantidadItems: items.length,
    ...calculateTotals({
      subtotal,
      ivaRate,
    }),
  };
};
